import { LABEL_ALIGNMENT } from '../constants.js';
import { LabelAlignment, LabelCoords } from '../types/range-legend.internal.js';

const DEFAULT_POSITION_Y_HORIZONTAL = 22;

/**
 * Returns the coordinates of the label, depending on the type of alignment,
 * positioned in an horizontal layout.
 */
export const getHorizontalLabelPosition = (
  labelWidth: number,
  itemStartPosition: number,
  itemEndPosition: number,
  alignment: LabelAlignment,
): Required<LabelCoords> => {
  const labelPositionY = DEFAULT_POSITION_Y_HORIZONTAL;

  switch (alignment) {
    case LABEL_ALIGNMENT.Start:
      return {
        x: itemStartPosition,
        y: labelPositionY,
      };
    case LABEL_ALIGNMENT.End: {
      return {
        x: Math.floor(itemEndPosition - labelWidth),
        y: labelPositionY,
      };
    }
    case LABEL_ALIGNMENT.Center: {
      return {
        x: Math.floor(itemEndPosition - labelWidth / 2),
        y: labelPositionY,
      };
    }
  }
};
